/**
 * Bing Maps Marker Component
 *
 * DRAGGING ARCHITECTURE:
 * =====================
 * This component implements MANUAL DRAGGING (Custom implementation) for all draggable markers.
 *
 * MANUAL DRAGGING (Custom implementation):
 *    - Used when: draggable=true
 *    - How: Implements custom mouse/keyboard handlers with position updates via map.tryLocationToPixel
 *    - Benefits: Supports constrained movement (horizontal/vertical only, min/max distance)
 *    - Why custom: Bing Maps doesn't provide built-in constrained dragging
 *    - Implementation: See handler functions below
 *
 * Code in this file is marked with comments:
 * - "General:" - Used for non-drag functionality or both drag modes
 * - "Manual dragging:" - Specific to custom constrained dragging
 */

import React, { forwardRef, useCallback, useEffect, useMemo, useRef } from 'react'
import { createPortal } from 'react-dom'
import { css } from '@linaria/core'
import PropTypes from 'prop-types'

import colors from '../../shared/Marker/colors'
import TeardropMarker from '../../shared/Marker/TeardropMarker'
import RoundMarker from '../../shared/Marker/RoundMarker'
import ResizeHandleMarker from '../../shared/Marker/ResizeHandleMarker'
import useMap from '../../shared/hooks/useMap'
import useMarker from '../../shared/hooks/useMarker'
import { constrainPosition, draggableDirectionsValidator } from '../../shared/Marker/draggableDirectionsConstraints'
import {
  EDGE_PAN_THRESHOLD,
  KEYBOARD_DRAG_MOVEMENT_MS,
  KEYBOARD_DRAG_STEP_FACTOR,
  MAP_PAN_SCALE,
} from '../../shared/utils'

const DEFAULT_TRANSLATE = '-50% -100%' // TeardropMarker (bottom-centered)
const ROUND_TRANSLATE = '-50% -50%' // RoundMarker/ResizeHandleMarker (centered)

// General: CSS class for all markers
// The .dragging class disables pointer events during drag to prevent interference with other markers
const markerClassName = css`
  cursor: pointer;
  line-height: 0;
  position: absolute;

  .dragging & {
    pointer-events: none;
  }
`

const interactableMarkerClassName = css`
  &:focus {
    outline: auto 2px Highlight;
    outline: -webkit-focus-ring-color auto 1px;
  }
`

const draggableMarkerClassName = css`
  cursor: grab;

  &:focus {
    outline: auto 2px Highlight;
    outline: -webkit-focus-ring-color auto 1px;
  }
`

function createContentElement() {
  const element = document.createElement('div')
  element.style.translate = DEFAULT_TRANSLATE
  element.classList.add(markerClassName)

  return element
}

function configureMarkerStyling({ color, draggable, interactable, marker }) {
  const { fill, invertFill } = colors[color] || colors.red
  marker.style['--fill'] = fill
  marker.style['--invertFill'] = invertFill

  if (interactable) {
    marker.classList.add(interactableMarkerClassName)
  }

  if (draggable) {
    marker.classList.add(draggableMarkerClassName)
  }

  if (interactable || draggable) {
    // Note, setting this to 'auto' causes the drag to not be smooth.
    // Set to empty string to just remove instead.
    marker.style.pointerEvents = ''
  } else {
    marker.style.pointerEvents = 'none'
  }
}

function updateMarkerPosition({ map, marker, positionRef }) {
  if (map && marker) {
    const location = new window.Microsoft.Maps.Location(positionRef.current.latitude, positionRef.current.longitude)
    const topLeft = map.tryLocationToPixel(location, window.Microsoft.Maps.PixelReference.control)

    if (!topLeft) {
      return
    }

    marker.style.left = `${topLeft.x}px`
    marker.style.top = `${topLeft.y}px`
  }
}

/**
 * Manual dragging: Automatically pan the map when marker gets near the edge
 *
 * WHY THIS EXISTS:
 * When dragging a marker, users often need to move it beyond the visible map area.
 * Without auto-panning, the marker would hit the edge and stop, forcing users to:
 * 1. Stop dragging
 * 2. Pan the map manually
 * 3. Resume dragging
 * This is poor UX for a common workflow.
 *
 * WHAT IT DOES:
 * Checks if the marker is within EDGE_PAN_THRESHOLD pixels of any map edge.
 * If so, pans the map in that direction to keep the marker visible and allow continued dragging.
 * Pan speed is proportional to how close the marker is to the edge.
 */
function moveMapIfNearEdge({ map, marker }) {
  const markerPixel = marker.getBoundingClientRect()
  const mapContainer = map.getRootElement()
  const mapBoundingRect = mapContainer.getBoundingClientRect()
  const { width, height, left, top } = mapBoundingRect

  let dx = 0
  let dy = 0

  // Calculate marker position relative to the map container
  const markerRelativeX = markerPixel.x - left
  const markerRelativeY = markerPixel.y - top

  if (markerRelativeX < EDGE_PAN_THRESHOLD) {
    dx = EDGE_PAN_THRESHOLD - markerRelativeX
  } else if (markerRelativeX > width - EDGE_PAN_THRESHOLD) {
    dx = width - EDGE_PAN_THRESHOLD - markerRelativeX
  }

  if (markerRelativeY < EDGE_PAN_THRESHOLD) {
    dy = EDGE_PAN_THRESHOLD - markerRelativeY
  } else if (markerRelativeY > height - EDGE_PAN_THRESHOLD) {
    dy = height - EDGE_PAN_THRESHOLD - markerRelativeY
  }

  if (dx !== 0 || dy !== 0) {
    // Move the map center in the same direction as the marker drag, and slow down the movement
    const center = map.getCenter()
    const centerPixel = map.tryLocationToPixel(
      new window.Microsoft.Maps.Location(center.latitude, center.longitude),
      window.Microsoft.Maps.PixelReference.control
    )

    if (!centerPixel) {
      return
    }

    const newCenterPixel = [centerPixel.x - dx / MAP_PAN_SCALE, centerPixel.y - dy / MAP_PAN_SCALE]
    const newCenter = map.tryPixelToLocation(
      new window.Microsoft.Maps.Point(newCenterPixel[0], newCenterPixel[1]),
      window.Microsoft.Maps.PixelReference.control
    )

    map.setView({ center: newCenter })
  }
}

/**
 * Manual dragging: Continuously update marker position during keyboard drag
 *
 * WHY WE USE setInterval:
 * Keyboard events fire repeatedly while a key is held, but the rate varies by OS and browser.
 * Users often hold multiple arrow keys simultaneously (e.g., up+right for diagonal movement).
 * Using setInterval gives us:
 * 1. Consistent, smooth movement at KEYBOARD_DRAG_MOVEMENT_MS intervals (60fps)
 * 2. Proper handling of multiple simultaneous key presses
 * 3. Independence from browser/OS key repeat rates
 *
 * HOW IT WORKS:
 * 1. Tracks all currently pressed arrow keys in pressedKeysRef
 * 2. Every interval, calculates cumulative movement from all pressed keys
 * 3. Applies constraints (direction, min/max distance)
 * 4. Updates marker position and triggers callbacks (onDrag, edge panning)
 */
function handleKeyboardDragMovement({
  constraintOrigin,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  event,
  map,
  moveMapCallback,
  onDrag,
  positionRef,
  pressedKeysRef,
  sharedPopper,
  updateMarkerPositionCallback,
}) {
  const zoom = map.getZoom()
  const step = KEYBOARD_DRAG_STEP_FACTOR / 2 ** (zoom + 2)

  return setInterval(() => {
    const newPosition = {
      latitude: positionRef.current.latitude,
      longitude: positionRef.current.longitude,
    }

    if (pressedKeysRef.current.has('ArrowUp')) newPosition.latitude += step
    if (pressedKeysRef.current.has('ArrowDown')) newPosition.latitude -= step
    if (pressedKeysRef.current.has('ArrowLeft')) newPosition.longitude -= step
    if (pressedKeysRef.current.has('ArrowRight')) newPosition.longitude += step

    const constrainedPosition = constrainPosition({
      draggableDirections,
      newPosition,
      originPosition: draggableConstraintOrigin || constraintOrigin,
      maxDistance: draggableMaxDistance,
      minDistance: draggableMinDistance,
    })

    positionRef.current = constrainedPosition
    updateMarkerPositionCallback()

    if (onDrag) {
      onDrag({
        position: {
          latitude: constrainedPosition.latitude,
          longitude: constrainedPosition.longitude,
        },
      })
    }

    sharedPopper.update({ event })
    moveMapCallback()
  }, KEYBOARD_DRAG_MOVEMENT_MS)
}

function cleanupKeyboardDragState({
  keyboardDragInitialPosition,
  keyboardDragMovementIntervalRef,
  pressedKeysRef,
  markerElement,
}) {
  keyboardDragInitialPosition.current = null
  pressedKeysRef.current.clear()

  if (keyboardDragMovementIntervalRef.current) {
    clearInterval(keyboardDragMovementIntervalRef.current)
    keyboardDragMovementIntervalRef.current = null
  }

  if (markerElement) {
    markerElement.style.zIndex = null
  }
}

/**
 * Manual dragging: Setup focus retention after drag cancellation
 *
 * WHY THIS EXISTS:
 * When a user cancels a keyboard drag with Escape, we restore the marker to its original position.
 * The marker can lose focus in several ways:
 * 1. When moved to its original position (which may be away from the cursor)
 * 2. When dragged out of view (partially or fully off-screen) during the drag
 * 3. When browser focus management changes focus asynchronously
 *
 * Without focus retention, keyboard users would have to tab back to find the marker, which is poor UX.
 *
 * WHAT IT DOES:
 * 1. Prevents blur events temporarily (100ms) to keep focus locked on the marker
 * 2. Allows Tab key to break out naturally for keyboard navigation
 * 3. Uses requestAnimationFrame and setTimeout to handle async focus issues
 *
 * WHY IT'S COMPLEX:
 * Browser focus management is async and blur can happen after we call focus().
 * We need multiple strategies (blur prevention + multiple focus calls) to ensure it works reliably.
 */
function setupFocusRetention(markerElement) {
  let blurPreventerActive = true

  // Prevent blur by intercepting the event and refocusing the marker
  const preventBlur = (e) => {
    if (blurPreventerActive && e.target === markerElement && e.relatedTarget !== markerElement) {
      e.preventDefault()
      e.stopImmediatePropagation()
      requestAnimationFrame(() => {
        if (blurPreventerActive) {
          markerElement.focus()
        }
      })
    }
  }

  // Allow Tab key to break out of focus lock for natural keyboard navigation
  const allowBlurOnTab = (e) => {
    if (e.key === 'Tab' || e.keyCode === 9) {
      blurPreventerActive = false
      markerElement.removeEventListener('blur', preventBlur, { capture: true })
      markerElement.removeEventListener('keydown', allowBlurOnTab, { capture: true })
    }
  }

  markerElement.addEventListener('blur', preventBlur, { capture: true })
  markerElement.addEventListener('keydown', allowBlurOnTab, { capture: true })

  markerElement.focus()

  // Use requestAnimationFrame and setTimeout to handle async focus issues
  requestAnimationFrame(() => {
    markerElement.focus()
    // After 100ms, give up and remove the blur preventer
    setTimeout(() => {
      blurPreventerActive = false
      markerElement.removeEventListener('blur', preventBlur, { capture: true })
      markerElement.removeEventListener('keydown', allowBlurOnTab, { capture: true })
    }, 100)
  })
}

function handleEnterKeyAsClick({ event, eventListeners }) {
  // Note: stopPropagation is needed to prevent this click from triggering on
  // the newly added `info` close button if one exists.  The reason this happens
  // is because the `info` close button receives focus when the `info` is opened,
  // and the `keydown` event bubbles up from the marker to the close button.
  event.stopPropagation()
  eventListeners.click(event)
}

function handleArrowKeysDuringDrag({
  constraintOrigin,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  event,
  keyboardDragMovementIntervalRef,
  map,
  moveMapCallback,
  onDrag,
  positionRef,
  pressedKeysRef,
  sharedPopper,
  updateMarkerPositionCallback,
}) {
  event.preventDefault()

  pressedKeysRef.current.add(event.code)

  if (!keyboardDragMovementIntervalRef.current) {
    keyboardDragMovementIntervalRef.current = handleKeyboardDragMovement({
      constraintOrigin,
      draggableConstraintOrigin,
      draggableDirections,
      draggableMaxDistance,
      draggableMinDistance,
      event,
      map,
      moveMapCallback,
      onDrag,
      positionRef,
      pressedKeysRef,
      sharedPopper,
      updateMarkerPositionCallback,
    })
  }
}

function handleEscapeToCancelDrag({
  event,
  keyboardDragInitialPosition,
  keyboardDragMovementIntervalRef,
  metadata,
  onDragEnd,
  positionRef,
  pressedKeysRef,
  updateMarkerPositionCallback,
}) {
  // Prevent all event handling first
  event.preventDefault()
  event.stopPropagation()
  if (event.stopImmediatePropagation) {
    event.stopImmediatePropagation()
  }

  positionRef.current = {
    latitude: keyboardDragInitialPosition.current.latitude,
    longitude: keyboardDragInitialPosition.current.longitude,
  }

  updateMarkerPositionCallback()

  // Call onDragEnd to clean up shadow circle
  if (onDragEnd) {
    onDragEnd({
      event,
      metadata,
      position: positionRef.current,
      cancelled: true,
    })
  }

  const markerElement = event.target
  cleanupKeyboardDragState({
    keyboardDragInitialPosition,
    keyboardDragMovementIntervalRef,
    pressedKeysRef,
    markerElement,
  })
  setupFocusRetention(markerElement)
}

/**
 * Manual dragging: Complete keyboard drag at current position
 *
 * skipNextClickRef EXPLANATION:
 * When a user completes a keyboard drag with Space/Enter, the keypress can bubble up
 * and trigger a click event on the map. This causes unintended behavior like:
 * - Opening info windows
 * - Triggering map click handlers
 * - Interfering with the drag workflow
 *
 * SOLUTION:
 * Set a flag (skipNextClickRef.current = true) that lasts 100ms to suppress the next click.
 * The map click handler checks this flag and ignores the click if it's set.
 * We use a 100ms timeout because events are processed asynchronously and the click
 * might not happen immediately. After 100ms, we clear the flag to allow normal clicks.
 */
function handleSpaceOrEnterToCompleteDrag({
  event,
  keyboardDragInitialPosition,
  keyboardDragMovementIntervalRef,
  metadata,
  onDragEnd,
  positionRef,
  pressedKeysRef,
  skipNextClickRef,
}) {
  // Prevent the map's onClick from firing after keyboard drag ends
  if (skipNextClickRef) {
    skipNextClickRef.current = true

    // Clear the flag after 100ms in case no click happens (avoid blocking future clicks)
    setTimeout(() => {
      skipNextClickRef.current = false
    }, 100)
  }

  onDragEnd?.({
    event,
    metadata,
    position: positionRef.current,
  })

  const markerElement = event.target
  cleanupKeyboardDragState({
    keyboardDragInitialPosition,
    keyboardDragMovementIntervalRef,
    pressedKeysRef,
    markerElement,
  })
}

/**
 * Manual dragging: Start keyboard drag mode with Alt+Space or Alt+Enter
 *
 * WHY ALT KEY IS REQUIRED:
 * Space and Enter keys have default behaviors that would conflict with drag initiation:
 * - Enter: Triggers click events (used for activating buttons, links, etc.)
 * - Space: Scrolls the page down (default browser behavior)
 *
 * By requiring Alt to be held, we:
 * 1. Avoid conflicts with default keyboard behaviors
 * 2. Prevent accidental drag initiation
 * 3. Follow accessibility patterns for modifier keys (like Ctrl+C for copy)
 *
 * Without Alt:
 * - Users pressing Enter would start drag instead of clicking
 * - Users pressing Space would start drag instead of scrolling
 * This would break basic keyboard navigation.
 */
function handleAltSpaceOrEnterToStartDrag({ event, keyboardDragInitialPosition, positionRef }) {
  keyboardDragInitialPosition.current = { ...positionRef.current }
  event.target.style.zIndex = 2 // Bring marker to front during drag
}

function handleKeyDown({
  constraintOrigin,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  event,
  eventListeners,
  keyboardDragInitialPosition,
  keyboardDragMovementIntervalRef,
  map,
  metadata,
  moveMapCallback,
  onDrag,
  onDragEnd,
  positionRef,
  pressedKeysRef,
  sharedPopper,
  skipNextClickRef,
  updateMarkerPositionCallback,
}) {
  const altKeyDown = event.altKey
  const escapeKeyDown = event.code === 'Escape'
  const enterKeyDown = event.code === 'Enter'
  const spaceKeyDown = event.code === 'Space'
  const spaceOrEnterKeyDown = spaceKeyDown || enterKeyDown
  const isDragging = Boolean(keyboardDragInitialPosition.current)

  // Treat the enter key as a click for keyboard accessibility
  if (enterKeyDown && !altKeyDown && !isDragging) {
    handleEnterKeyAsClick({ event, eventListeners })
    return
  }

  const arrowKeys = ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight']
  const isArrowKey = arrowKeys.includes(event.code)

  if (isArrowKey && isDragging) {
    handleArrowKeysDuringDrag({
      constraintOrigin,
      draggableConstraintOrigin,
      draggableDirections,
      draggableMaxDistance,
      draggableMinDistance,
      event,
      keyboardDragMovementIntervalRef,
      map,
      moveMapCallback,
      onDrag,
      positionRef,
      pressedKeysRef,
      sharedPopper,
      updateMarkerPositionCallback,
    })
    return
  }

  if (escapeKeyDown && isDragging) {
    handleEscapeToCancelDrag({
      event,
      keyboardDragInitialPosition,
      keyboardDragMovementIntervalRef,
      metadata,
      onDragEnd,
      positionRef,
      pressedKeysRef,
      updateMarkerPositionCallback,
    })
    return
  }

  if (spaceOrEnterKeyDown && isDragging) {
    handleSpaceOrEnterToCompleteDrag({
      event,
      keyboardDragInitialPosition,
      keyboardDragMovementIntervalRef,
      metadata,
      onDragEnd,
      positionRef,
      pressedKeysRef,
      skipNextClickRef,
    })
    return
  }

  if (altKeyDown && spaceOrEnterKeyDown) {
    handleAltSpaceOrEnterToStartDrag({ event, keyboardDragInitialPosition, positionRef })
  }
}

function handleKeyUp({ event, pressedKeysRef, keyboardDragMovementIntervalRef }) {
  const arrowKeys = ['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight']
  if (arrowKeys.includes(event.code)) {
    pressedKeysRef.current.delete(event.code)
    if (pressedKeysRef.current.size === 0) {
      clearInterval(keyboardDragMovementIntervalRef.current)
      keyboardDragMovementIntervalRef.current = null
    }
  }
}

/**
 * Manual dragging: Shared function to update marker position from pixel coordinates
 * Used by both mouse and touch drag handlers
 */
function updateMarkerFromPixelCoordinates({
  constraintOriginRef,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  map,
  marker,
  onDrag,
  pixelX,
  pixelY,
  positionRef,
}) {
  const pixel = new window.Microsoft.Maps.Point(pixelX, pixelY)
  const location = map.tryPixelToLocation(pixel, window.Microsoft.Maps.PixelReference.control)

  if (location) {
    const newPosition = {
      latitude: location.latitude,
      longitude: location.longitude,
    }

    const constrainedPosition = constrainPosition({
      draggableDirections,
      newPosition,
      originPosition: draggableConstraintOrigin || constraintOriginRef.current,
      maxDistance: draggableMaxDistance,
      minDistance: draggableMinDistance,
    })

    positionRef.current = constrainedPosition

    // Update marker DOM position
    const constrainedLocation = new window.Microsoft.Maps.Location(
      constrainedPosition.latitude,
      constrainedPosition.longitude
    )

    const constrainedPixel = map.tryLocationToPixel(constrainedLocation, window.Microsoft.Maps.PixelReference.control)
    if (constrainedPixel) {
      marker.style.left = `${constrainedPixel.x}px`
      marker.style.top = `${constrainedPixel.y}px`
    }

    if (onDrag) {
      onDrag({
        position: constrainedPosition,
      })
    }
  }
}

function createMouseDragHandlers({
  constraintOriginRef,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  draggingRef,
  map,
  marker,
  metadata,
  moveMapCallback,
  onDrag,
  onDragEnd,
  positionRef,
  sharedPopper,
  skipNextClickRef,
}) {
  let mouseDown = false
  let offsetX
  let offsetY
  let draggingAdded = false

  function mouseMoveHandler(event) {
    if (!mouseDown) return

    if (!draggingAdded) {
      draggingAdded = true
      map.getRootElement().classList.add('dragging')
      draggingRef.current = true
    }

    // Get fresh map offset in case DOM structure changed (e.g., sidesheet opened)
    const mapBoundingClientRect = map.getRootElement().getBoundingClientRect()
    const mapOffsetX = mapBoundingClientRect.left
    const mapOffsetY = mapBoundingClientRect.top

    const pixelX = event.clientX - offsetX - mapOffsetX
    const pixelY = event.clientY - offsetY - mapOffsetY

    updateMarkerFromPixelCoordinates({
      constraintOriginRef,
      draggableConstraintOrigin,
      draggableDirections,
      draggableMaxDistance,
      draggableMinDistance,
      map,
      marker,
      onDrag: onDrag
        ? (dragEvent) => {
            onDrag({
              ...dragEvent,
              event,
              metadata: metadata.current,
            })
          }
        : undefined,
      pixelX,
      pixelY,
      positionRef,
    })

    marker.style.zIndex = 2

    sharedPopper.update({ event })
    moveMapCallback()
  }

  function mouseUpHandler(event) {
    if (!mouseDown) return

    draggingAdded = false
    mouseDown = false

    // This prevents the map's onClick from firing after the marker drag ends
    if (skipNextClickRef) {
      skipNextClickRef.current = true

      // Clear the flag after a short delay in case no click happens
      setTimeout(() => {
        skipNextClickRef.current = false
      }, 100)
    }

    onDragEnd?.({
      event,
      metadata: metadata.current,
      position: positionRef.current,
    })

    map.getRootElement().classList.remove('dragging')
    draggingRef.current = false

    marker.style.zIndex = null
  }

  function mouseDownHandler(event) {
    mouseDown = true

    marker.style.zIndex = 2

    const markerBoundingRect = marker.getBoundingClientRect()

    offsetX = event.clientX - markerBoundingRect.left - markerBoundingRect.width / 2

    const offsetYDivisor = marker.style.translate === ROUND_TRANSLATE ? 2 : 1
    offsetY = event.clientY - markerBoundingRect.top - markerBoundingRect.height / offsetYDivisor
  }

  return { mouseMoveHandler, mouseUpHandler, mouseDownHandler }
}

function createTouchDragHandlers({
  constraintOriginRef,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  draggingRef,
  map,
  marker,
  metadata,
  moveMapCallback,
  onDrag,
  onDragEnd,
  positionRef,
  sharedPopper,
  skipNextClickRef,
}) {
  let touchActive = false
  let offsetX
  let offsetY
  let draggingAdded = false

  function touchMoveHandler(event) {
    if (!touchActive || event.touches.length !== 1) return

    // Prevent default to stop scrolling
    event.preventDefault()

    if (!draggingAdded) {
      draggingAdded = true
      map.getRootElement().classList.add('dragging')
      draggingRef.current = true
    }

    // Get fresh map offset in case DOM structure changed
    const mapBoundingClientRect = map.getRootElement().getBoundingClientRect()
    const mapOffsetX = mapBoundingClientRect.left
    const mapOffsetY = mapBoundingClientRect.top

    const touch = event.touches[0]
    const pixelX = touch.clientX - offsetX - mapOffsetX
    const pixelY = touch.clientY - offsetY - mapOffsetY

    updateMarkerFromPixelCoordinates({
      constraintOriginRef,
      draggableConstraintOrigin,
      draggableDirections,
      draggableMaxDistance,
      draggableMinDistance,
      map,
      marker,
      onDrag: onDrag
        ? (dragEvent) => {
            onDrag({
              ...dragEvent,
              event,
              metadata: metadata.current,
            })
          }
        : undefined,
      pixelX,
      pixelY,
      positionRef,
    })

    marker.style.zIndex = 2

    // Create a synthetic event for sharedPopper
    sharedPopper.update({ event: { clientX: touch.clientX, clientY: touch.clientY } })
    moveMapCallback()
  }

  function touchEndHandler(event) {
    if (!touchActive) return

    draggingAdded = false
    touchActive = false

    // This prevents the map's onClick from firing after the marker drag ends
    if (skipNextClickRef) {
      skipNextClickRef.current = true

      // Clear the flag after a short delay in case no click happens
      setTimeout(() => {
        skipNextClickRef.current = false
      }, 100)
    }

    onDragEnd?.({
      event,
      metadata: metadata.current,
      position: positionRef.current,
    })

    map.getRootElement().classList.remove('dragging')
    draggingRef.current = false

    marker.style.zIndex = null
  }

  function touchStartHandler(event) {
    if (event.touches.length !== 1) return

    // Prevent default to stop scrolling/zooming
    event.preventDefault()

    touchActive = true

    marker.style.zIndex = 2

    const markerBoundingRect = marker.getBoundingClientRect()
    const touch = event.touches[0]

    offsetX = touch.clientX - markerBoundingRect.left - markerBoundingRect.width / 2

    const offsetYDivisor = marker.style.translate === ROUND_TRANSLATE ? 2 : 1
    offsetY = touch.clientY - markerBoundingRect.top - markerBoundingRect.height / offsetYDivisor
  }

  return { touchMoveHandler, touchEndHandler, touchStartHandler }
}

function addEventListeners({ eventListeners, eventListenersRef, events, marker }) {
  eventListenersRef.current.forEach(([event, listener, options]) => {
    marker.removeEventListener(event, listener, options)
  })

  eventListenersRef.current = []

  Object.entries(eventListeners).forEach(([event, listener]) => {
    const options = event === 'keydown' ? { capture: true } : undefined
    marker.addEventListener(event, listener, options)
    eventListenersRef.current.push([event, listener, options])
  })

  Object.entries(events).forEach(([event, handler]) => {
    const options = event === 'keydown' ? { capture: true } : undefined
    marker.addEventListener(event, handler, options)
    eventListenersRef.current.push([event, handler, options])
  })
}

function clearEventListeners({ eventListenersRef, marker }) {
  eventListenersRef.current.forEach(([event, listener, options]) => {
    marker?.removeEventListener(event, listener, options)
  })

  eventListenersRef.current = []
}

function updateMarkerDraggableState({ draggable, marker }) {
  if (draggable) {
    marker.classList.add(draggableMarkerClassName)
  } else {
    marker.classList.remove(draggableMarkerClassName)
  }
}

function updateMarkerTranslate({ cluster, draggableDirections, imageSrc, marker, proximity }) {
  if (cluster || imageSrc || proximity || draggableDirections) {
    marker.style.translate = ROUND_TRANSLATE
  } else {
    marker.style.translate = DEFAULT_TRANSLATE
  }
}

function updateMarkerInteractableState({ interactable, marker }) {
  if (interactable) {
    marker.classList.add(interactableMarkerClassName)
  } else {
    marker.classList.remove(interactableMarkerClassName)
  }

  if (interactable || marker.classList.contains(draggableMarkerClassName)) {
    // Note, setting this to 'auto' causes the drag to not be smooth.
    // Set to empty string to just remove instead.
    marker.style.pointerEvents = ''
  } else {
    marker.style.pointerEvents = 'none'
  }
}

function updateMarkerAccessibility({ ariaLabel, marker, title, interactable, draggable }) {
  marker.setAttribute('role', interactable || draggable ? 'button' : 'img')
  marker.setAttribute('aria-label', ariaLabel)
  marker.setAttribute('tabindex', interactable || draggable ? '0' : '-1')

  if (typeof title === 'string') {
    marker.setAttribute('title', title)
  }
}

function useMarkerElement({ color, draggable, id, interactable, map, setMarker, sharedPopper }) {
  const contentRef = useRef(null)

  if (contentRef.current === null) {
    contentRef.current = createContentElement()
  }

  // Create the marker
  useEffect(() => {
    let popperUpdateListener

    const rootElement = map?.getRootElement()
    if (rootElement) {
      rootElement.appendChild(contentRef.current)

      popperUpdateListener = window.Microsoft.Maps.Events.addHandler(map, 'viewchange', () => {
        sharedPopper.update({ event: { target: contentRef.current } })
      })

      if (id) {
        contentRef.current.id = id
      }

      configureMarkerStyling({ color, draggable, interactable, marker: contentRef.current })

      setMarker(contentRef.current)
    }

    return () => {
      window.Microsoft?.Maps?.Events?.removeHandler?.(popperUpdateListener)

      if (rootElement?.contains(contentRef.current)) {
        contentRef.current.remove()
      }
    }
  }, [id, map, setMarker, sharedPopper, color, draggable, interactable])

  return contentRef.current
}

function useMarkerPositioning({ map, updateMarkerPositionCallback }) {
  const draggingRef = useRef(false)

  // Update the marker position
  useEffect(() => {
    let viewChangeListener
    let viewRenderedListener

    if (map) {
      updateMarkerPositionCallback()

      const handleViewUpdate = () => {
        if (!draggingRef.current) {
          updateMarkerPositionCallback()
        }
      }

      viewChangeListener = window.Microsoft.Maps.Events.addHandler(map, 'viewchange', handleViewUpdate)
      viewRenderedListener = window.Microsoft.Maps.Events.addHandler(map, 'viewrendered', handleViewUpdate)
    }

    return () => {
      window.Microsoft?.Maps?.Events?.removeHandler?.(viewChangeListener)
      window.Microsoft?.Maps?.Events?.removeHandler?.(viewRenderedListener)
    }
  }, [map, updateMarkerPositionCallback])

  return draggingRef
}

function useMarkerDragging({
  constraintOriginRef,
  draggable,
  draggableConstraintOrigin,
  draggableDirections,
  draggableMaxDistance,
  draggableMinDistance,
  draggingRef,
  map,
  marker,
  metadata,
  moveMapCallback,
  onDrag,
  onDragEnd,
  positionRef,
  sharedPopper,
  skipNextClickRef,
}) {
  // Store callbacks in refs to prevent re-creating handlers on every render
  const onDragRef = useRef(onDrag)
  const onDragEndRef = useRef(onDragEnd)
  const metadataRef = useRef(metadata)
  const handlersRef = useRef(null)

  // Update refs when callbacks change
  useEffect(() => {
    onDragRef.current = onDrag
    onDragEndRef.current = onDragEnd
    metadataRef.current = metadata
  }, [onDrag, onDragEnd, metadata])

  useEffect(() => {
    if (!map || !marker || !draggable) {
      return undefined
    }

    // If handlers already exist, reuse them instead of creating new ones
    if (!handlersRef.current) {
      const { mouseMoveHandler, mouseUpHandler, mouseDownHandler } = createMouseDragHandlers({
        constraintOriginRef,
        draggableConstraintOrigin,
        draggableDirections,
        draggableMaxDistance,
        draggableMinDistance,
        draggingRef,
        map,
        marker,
        metadata: metadataRef,
        moveMapCallback,
        onDrag: (args) => onDragRef.current?.(args),
        onDragEnd: (args) => onDragEndRef.current?.(args),
        positionRef,
        sharedPopper,
        skipNextClickRef,
      })

      // Create touch handlers
      const { touchMoveHandler, touchEndHandler, touchStartHandler } = createTouchDragHandlers({
        constraintOriginRef,
        draggableConstraintOrigin,
        draggableDirections,
        draggableMaxDistance,
        draggableMinDistance,
        draggingRef,
        map,
        marker,
        metadata: metadataRef,
        moveMapCallback,
        onDrag: (args) => onDragRef.current?.(args),
        onDragEnd: (args) => onDragEndRef.current?.(args),
        positionRef,
        sharedPopper,
        skipNextClickRef,
      })

      handlersRef.current = {
        mouseMoveHandler,
        mouseUpHandler,
        mouseDownHandler,
        touchMoveHandler,
        touchEndHandler,
        touchStartHandler,
      }

      // Add mouse event listeners
      document.addEventListener('mousemove', mouseMoveHandler)
      document.addEventListener('mouseup', mouseUpHandler)
      marker.addEventListener('mousedown', mouseDownHandler)
      marker.addEventListener('mousemove', mouseMoveHandler)

      // Add touch event listeners with passive: false to allow preventDefault
      document.addEventListener('touchmove', touchMoveHandler, { passive: false })
      document.addEventListener('touchend', touchEndHandler)
      marker.addEventListener('touchstart', touchStartHandler, { passive: false })
      marker.addEventListener('touchmove', touchMoveHandler, { passive: false })
    }

    return () => {
      // CRITICAL: Don't remove event listeners if drag is active
      // Removing listeners mid-drag would break the drag operation - touchmove/touchend
      // events would no longer be captured, leaving the marker in a stuck dragging state
      // eslint-disable-next-line react-hooks/exhaustive-deps -- We intentionally check the ref at cleanup time
      if (draggingRef.current) {
        return
      }

      if (handlersRef.current) {
        const {
          mouseMoveHandler,
          mouseUpHandler,
          mouseDownHandler,
          touchMoveHandler,
          touchEndHandler,
          touchStartHandler,
        } = handlersRef.current

        // Remove mouse listeners
        marker.removeEventListener('mousedown', mouseDownHandler)
        marker.removeEventListener('mousemove', mouseMoveHandler)
        document.removeEventListener('mousemove', mouseMoveHandler)
        document.removeEventListener('mouseup', mouseUpHandler)

        // Remove touch listeners
        marker.removeEventListener('touchstart', touchStartHandler)
        marker.removeEventListener('touchmove', touchMoveHandler)
        document.removeEventListener('touchmove', touchMoveHandler)
        document.removeEventListener('touchend', touchEndHandler)

        handlersRef.current = null
      }
    }
  }, [
    constraintOriginRef,
    draggable,
    draggableConstraintOrigin,
    draggableDirections,
    draggableMaxDistance,
    draggableMinDistance,
    draggingRef,
    map,
    marker,
    moveMapCallback,
    positionRef,
    sharedPopper,
    skipNextClickRef,
  ])
}

function useMarkerEventListeners({ events, eventListeners, marker }) {
  const eventListenersRef = useRef([])

  // Add event listeners
  useEffect(() => {
    if (marker) {
      addEventListeners({ eventListeners, eventListenersRef, events, marker })
    }

    return () => {
      clearEventListeners({ eventListenersRef, marker })
    }
  }, [events, eventListeners, marker])
}

function useMapClickBlur({ marker, map }) {
  // Handle map click to blur marker
  useEffect(() => {
    if (!map || !marker) {
      return undefined
    }

    const mapClickListener = window.Microsoft.Maps.Events.addHandler(map, 'click', (event) => {
      if (!marker.contains(event.target.element) && document.activeElement === marker) {
        marker.blur()
      }
    })

    return () => {
      window.Microsoft?.Maps?.Events?.removeHandler?.(mapClickListener)
    }
  }, [map, marker])
}

function useKeyboardDragCleanup({ keyboardDragMovementIntervalRef }) {
  // Cleanup keyboard drag interval on unmount
  useEffect(() => {
    return () => {
      clearInterval(keyboardDragMovementIntervalRef.current)
      keyboardDragMovementIntervalRef.current = null
    }
  }, [keyboardDragMovementIntervalRef])
}

function useMarkerUpdates({
  ariaLabel,
  cluster,
  draggable,
  draggableDirections,
  imageSrc,
  interactable,
  marker,
  proximity,
  title,
}) {
  // Update marker accessibility and draggable state
  useEffect(() => {
    if (marker) {
      updateMarkerAccessibility({ ariaLabel, marker, title, interactable, draggable })
      updateMarkerDraggableState({ draggable, marker })
      updateMarkerInteractableState({ interactable, marker })
      updateMarkerTranslate({ cluster, draggableDirections, imageSrc, marker, proximity })
    }
  }, [ariaLabel, cluster, draggable, draggableDirections, imageSrc, interactable, marker, proximity, title])
}

const Marker = forwardRef((props, ref) => {
  const {
    ariaLabel,
    chars,
    cluster,
    color,
    draggable,
    draggableConstraintOrigin,
    draggableDirections,
    draggableMaxDistance,
    draggableMinDistance,
    focused,
    Icon,
    id,
    imageSrc,
    latitude,
    longitude,
    metadata,
    onDrag,
    onDragEnd,
    proximity,
    testId,
    title,
  } = props

  const keyboardDragInitialPosition = useRef()
  const keyboardDragMovementIntervalRef = useRef()
  const pressedKeysRef = useRef(new Set())
  const constraintOriginRef = useRef({ latitude, longitude })
  const { map, skipNextClickRef } = useMap()

  const { eventListeners, interactable, marker, positionRef, setMarker, sharedPopper } = useMarker(props, ref)

  // Update constraint origin when position changes via props
  useEffect(() => {
    constraintOriginRef.current = { latitude, longitude }
  }, [latitude, longitude])

  const updateMarkerPositionCallback = useCallback(() => {
    updateMarkerPosition({ map, marker, positionRef })
  }, [map, marker, positionRef])

  const moveMapCallback = useCallback(() => {
    moveMapIfNearEdge({ map, marker })
  }, [map, marker])

  const events = useMemo(() => {
    return {
      blur: () => {
        if (keyboardDragInitialPosition.current) {
          keyboardDragInitialPosition.current = null
          pressedKeysRef.current.clear()

          if (keyboardDragMovementIntervalRef.current) {
            clearInterval(keyboardDragMovementIntervalRef.current)
            keyboardDragMovementIntervalRef.current = null
          }
        }
      },
      keydown: (event) => {
        handleKeyDown({
          constraintOrigin: constraintOriginRef.current,
          draggableConstraintOrigin,
          draggableDirections,
          draggableMaxDistance,
          draggableMinDistance,
          event,
          eventListeners,
          keyboardDragInitialPosition,
          keyboardDragMovementIntervalRef,
          map,
          metadata,
          moveMapCallback,
          onDrag,
          onDragEnd,
          positionRef,
          pressedKeysRef,
          sharedPopper,
          skipNextClickRef,
          updateMarkerPositionCallback,
        })
      },
      keyup: (event) => {
        handleKeyUp({ event, pressedKeysRef, keyboardDragMovementIntervalRef })
      },
    }
  }, [
    draggableConstraintOrigin,
    draggableDirections,
    draggableMaxDistance,
    draggableMinDistance,
    eventListeners,
    map,
    metadata,
    moveMapCallback,
    onDrag,
    onDragEnd,
    positionRef,
    sharedPopper,
    skipNextClickRef,
    updateMarkerPositionCallback,
  ])

  const contentElement = useMarkerElement({ color, draggable, id, interactable, map, setMarker, sharedPopper })
  const draggingRef = useMarkerPositioning({ map, updateMarkerPositionCallback })

  useMarkerDragging({
    constraintOriginRef,
    draggable,
    draggableConstraintOrigin,
    draggableDirections,
    draggableMaxDistance,
    draggableMinDistance,
    draggingRef,
    map,
    marker,
    metadata,
    moveMapCallback,
    onDrag,
    onDragEnd,
    positionRef,
    sharedPopper,
    skipNextClickRef,
  })
  useMarkerEventListeners({ events, eventListeners, marker })
  useMapClickBlur({ marker, map })
  useKeyboardDragCleanup({ keyboardDragMovementIntervalRef })
  useMarkerUpdates({
    ariaLabel,
    cluster,
    draggable,
    draggableDirections,
    imageSrc,
    interactable,
    marker,
    proximity,
    title,
  })

  const displayMarker = useMemo(() => {
    if (draggableDirections) {
      return <ResizeHandleMarker color={color} draggableDirections={draggableDirections} />
    }

    if (cluster || imageSrc || proximity) {
      return (
        <RoundMarker
          chars={chars}
          cluster={cluster}
          color={color}
          draggable={draggable}
          draggableDirections={draggableDirections}
          focused={focused}
          Icon={Icon}
          imageSrc={imageSrc}
          interactable={interactable}
          proximity={proximity}
          testId={testId}
        />
      )
    }

    return (
      <TeardropMarker
        chars={chars}
        color={color}
        draggable={draggable}
        draggableDirections={draggableDirections}
        focused={focused}
        Icon={Icon}
        interactable={interactable}
        testId={testId}
      />
    )
  }, [Icon, chars, cluster, color, draggable, draggableDirections, focused, imageSrc, interactable, proximity, testId])

  return createPortal(displayMarker, contentElement)
})

Marker.displayName = 'Marker'

export default Marker

Marker.propTypes = {
  ariaLabel: PropTypes.string.isRequired,
  chars: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  cluster: PropTypes.bool,
  color: PropTypes.oneOf(['blue', 'gray', 'green', 'purple', 'red', 'yellow']),
  draggable: PropTypes.bool,
  draggableConstraintOrigin: PropTypes.shape({
    latitude: PropTypes.number.isRequired,
    longitude: PropTypes.number.isRequired,
  }),
  draggableDirections: draggableDirectionsValidator,
  draggableMaxDistance: PropTypes.number,
  draggableMinDistance: PropTypes.number,
  focused: PropTypes.bool,
  Icon: PropTypes.func,
  id: PropTypes.string,
  imageSrc: PropTypes.string,
  info: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),
  label: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),
  latitude: PropTypes.number.isRequired,
  longitude: PropTypes.number.isRequired,
  metadata: PropTypes.any,
  onBlur: PropTypes.func,
  onClick: PropTypes.func,
  onDrag: PropTypes.func,
  onDragEnd: PropTypes.func,
  onFocus: PropTypes.func,
  onInfoClosed: PropTypes.func,
  onMouseEnter: PropTypes.func,
  onMouseLeave: PropTypes.func,
  proximity: PropTypes.bool,
  testId: PropTypes.string,
  title: PropTypes.string,
}
